#include <stdio.h>
#include <string.h>
#define MAXN 1000
#define MOD 1000000080798150871ULL
static unsigned long long Cbin[MAXN+1][MAXN+1];

void build_binom(int n){
    for(int i=0;i<=n;i++){
        Cbin[i][0]=Cbin[i][i]=1ULL;
        for(int j=1;j<i;j++){
            unsigned long long v = Cbin[i-1][j-1] + Cbin[i-1][j];
            if(v>=MOD) v-=MOD;
            Cbin[i][j]=v;
        }
    }
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,M,L,K; scanf("%d %d %d %d",&N,&M,&L,&K);
        static char grid[MAXN][4];
        for(int i=0;i<N;i++) scanf("%s",grid[i]);
        build_binom(N);
        unsigned long long ans=0ULL;
        // enumerate column subsets
        for(int mask=0; mask<(1<<M); ++mask){
            if(__builtin_popcount(mask)!=K) continue;
            int cnt=0;
            for(int r=0;r<N;r++){
                int ok=1;
                for(int c=0;c<M;c++) if(mask>>c & 1){
                    if(grid[r][c]!='1'){ ok=0; break; }
                }
                if(ok) cnt++;
            }
            if(cnt>=L) ans = (ans + Cbin[cnt][L]) % MOD;
        }
        printf("%llu\n", ans);
    }
    return 0;
}

