import java.io.*;
import java.util.*;

public class Main {
    static final long MOD = 1000000080798150871L;
    static long[][] Cbin = new long[1001][1001];
    static void buildBinom(int n){
        for(int i=0;i<=n;i++){
            Cbin[i][0]=Cbin[i][i]=1L;
            for(int j=1;j<i;j++){
                long v = Cbin[i-1][j-1] + Cbin[i-1][j];
                if(v>=MOD) v-=MOD;
                Cbin[i][j]=v;
            }
        }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while(T-- > 0){
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int M = Integer.parseInt(st.nextToken());
            int L = Integer.parseInt(st.nextToken());
            int K = Integer.parseInt(st.nextToken());
            char[][] g = new char[N][];
            for(int i=0;i<N;i++) g[i] = br.readLine().toCharArray();
            buildBinom(N);
            long ans = 0L;
            int totalMask = 1<<M;
            for(int mask=0; mask<totalMask; mask++){
                if(Integer.bitCount(mask)!=K) continue;
                int cnt = 0;
                for(int r=0;r<N;r++){
                    boolean ok = true;
                    for(int c=0;c<M;c++) if(((mask>>c)&1)==1){
                        if(g[r][c]!='1'){ ok=false; break; }
                    }
                    if(ok) cnt++;
                }
                if(cnt>=L) ans = (ans + Cbin[cnt][L]) % MOD;
            }
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }
}

