import sys
MOD = 1000000080798150871
MAXN = 1000
# pre‑compute Pascal triangle once up to MAXN
C = [[0]*(MAXN+1) for _ in range(MAXN+1)]
for i in range(MAXN+1):
    C[i][0] = C[i][i] = 1
    for j in range(1, i):
        v = C[i-1][j-1] + C[i-1][j]
        if v >= MOD:
            v -= MOD
        C[i][j] = v

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); L = int(next(it)); K = int(next(it))
        grid = [list(next(it).strip()) for _ in range(N)]
        ans = 0
        for mask in range(1<<M):
            if bin(mask).count('1') != K:
                continue
            cnt = 0
            for r in range(N):
                ok = True
                for c in range(M):
                    if (mask>>c) & 1:
                        if grid[r][c] != '1':
                            ok = False
                            break
                if ok:
                    cnt += 1
            if cnt >= L:
                ans = (ans + C[cnt][L]) % MOD
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

